import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useTable, useFilters, useGlobalFilter, useAsyncDebounce } from 'react-table';
import { Input, Button, Table, Space, Modal, Form, notification } from 'antd';

const { Search } = Input;
const { confirm } = Modal;

function MaterialList() {
  const [material, setMaterial] = useState([]);
  const [newMaterialData, setNewMaterialData] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: '',
  });
  const [editMaterialData, setEditMaterialData] = useState(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  useEffect(() => {
    fetchMaterial();
  }, []);

  const fetchMaterial = () => {
    axios
      .get('http://localhost:8081')
      .then((res) => setMaterial(res.data))
      .catch((err) => console.log(err));
  };

  const handleAddMaterial = () => {
    axios
      .post('http://localhost:8081', newMaterialData)
      .then((res) => {
        setMaterial((prevMaterial) => [...prevMaterial, res.data]);
        setNewMaterialData({
          matid: '',
          name: '',
          description: '',
          unit_of_measure: '',
          price_per_unit: 0,
          recent_vendor: '',
        });
        setIsAddModalOpen(false);
        notification.success({ message: 'Material added successfully' });
      })
      .catch((err) => console.log(err));
  };

  const handleEditMaterial = () => {
    const { id } = editMaterialData;
    axios
      .put(`http://localhost:8081/${id}`, editMaterialData)
      .then(() => {
        const updatedMaterial = material.map((m) => (m.id === id ? editMaterialData : m));
        setMaterial(updatedMaterial);
        setEditMaterialData(null);
        setIsEditModalOpen(false);
        notification.success({ message: 'Material updated successfully' });
      })
      .catch((err) => console.log(err));
  };

  const handleDeleteMaterial = useCallback((id) => {
    confirm({
      title: 'Delete Material',
      content: 'Are you sure you want to delete this material?',
      okText: 'Delete',
      okType: 'danger',
      cancelText: 'Cancel',
      onOk() {
        axios
          .delete(`http://localhost:8081/${id}`)
          .then(() => {
            const updatedMaterial = material.filter((m) => m.id !== id);
            setMaterial(updatedMaterial);
            notification.success({ message: 'Material deleted successfully' });
          })
          .catch((err) => console.log(err));
      },
    });
  }, [material]);

  const handleInputChange = (e, type) => {
    const { name, value } = e.target;
    const data = type === 'add' ? newMaterialData : editMaterialData;
    const updatedData = { ...data, [name]: value };
    if (type === 'add') {
      setNewMaterialData(updatedData);
    } else {
      setEditMaterialData(updatedData);
    }
  };

  const columns = React.useMemo(
    () => [
      {
        Header: 'Material ID',
        accessor: 'matid',
      },
      {
        Header: 'Name',
        accessor: 'name',
      },
      {
        Header: 'Description',
        accessor: 'description',
      },
      {
        Header: 'Unit of Measure',
        accessor: 'unit_of_measure',
      },
      {
        Header: 'Price per Unit',
        accessor: 'price_per_unit',
      },
      {
        Header: 'Recent Vendor',
        accessor: 'recent_vendor',
      },
      {
        Header: 'Actions',
        Cell: ({ row }) => (
          <Space size="middle">
            <Button type="primary" onClick={() => showEditModal(row.original)}>
              Edit
            </Button>
            <Button type="danger" onClick={() => handleDeleteMaterial(row.original.id)}>
              Delete
            </Button>
          </Space>
        ),
      },
    ],
    [handleDeleteMaterial]
  );

  const data = React.useMemo(() => material, [material]);

  const defaultColumn = React.useMemo(
    () => ({
      Filter: DefaultColumnFilter,
    }),
    []
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    state,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data,
      defaultColumn,
    },
    useFilters,
    useGlobalFilter
  );

  const { globalFilter } = state;

  const handleGlobalFilterChange = useAsyncDebounce((value) => {
    setGlobalFilter(value || undefined);
  }, 200);

  const showAddModal = () => {
    setIsAddModalOpen(true);
  };

  const handleAddModalCancel = () => {
    setIsAddModalOpen(false);
  };

  const showEditModal = (materialData) => {
    setEditMaterialData(materialData);
    setIsEditModalOpen(true);
  };

  const handleEditModalCancel = () => {
    setEditMaterialData(null);
    setIsEditModalOpen(false);
  };

  return (
    <div>
      <div style={{ marginBottom: '16px' }}>
        <Search
          placeholder="Search..."
          value={globalFilter || ''}
          onChange={(e) => handleGlobalFilterChange(e.target.value)}
          allowClear
        />
        <Button type="primary" onClick={showAddModal} style={{ marginLeft: '16px' }}>
          Add Material
        </Button>
      </div>

      <Table {...getTableProps()} dataSource={rows} loading={!material.length}>
        {headerGroups.map((headerGroup) => (
          <tr {...headerGroup.getHeaderGroupProps()}>
            {headerGroup.headers.map((column) => (
              <th {...column.getHeaderProps()}>{column.render('Header')}</th>
            ))}
          </tr>
        ))}

        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </Table>

      <Modal
        title="Add Material"
        visible={isAddModalOpen}
        onOk={handleAddMaterial}
        onCancel={handleAddModalCancel}
      >
        <Form>
          {/* Add Material form fields */}
        </Form>
      </Modal>

      <Modal
        title="Edit Material"
        visible={isEditModalOpen}
        onOk={handleEditMaterial}
        onCancel={handleEditModalCancel}
      >
        <Form>
          {/* Edit Material form fields */}
        </Form>
      </Modal>
    </div>
  );
}

export default MaterialList;
